@Service
public class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public MfaService(UserRepository userRepository, BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public List<String> generateBackupCodes(Long userId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));

        List<String> codes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            codes.add(generateRandomCode());
        }

        for (String code : codes) {
            BackupCode backupCode = new BackupCode(user, code);
            backupCodeRepository.save(backupCode);
        }

        return codes;
    }

    private String generateRandomCode() {
        StringBuilder code = new StringBuilder();
        Random random = new Random();
        for (int i = 0; i < 8; i++) {
            code.append(random.nextInt(10));
        }
        return code.toString();
    }

    public boolean validateBackupCode(String code) {
        Optional<BackupCode> backupCode = backupCodeRepository.findByCodeAndUsedFalse(code);
        if (backupCode.isPresent()) {
            BackupCode bc = backupCode.get();
            if (bc.getExpiresAt().isAfter(LocalDateTime.now())) {
                bc.setUsed(true);
                backupCodeRepository.save(bc);
                return true;
            }
        }
        return false;
    }

    public void enableMfa(Long userId, String secret) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));
        user.setMfaSecret(secret);
        user.setMfaEnabled(true);
        userRepository.save(user);
    }

    public void disableMfa(Long userId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));
        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam Long userId, @RequestParam String secret) {
        try {
            mfaService.enableMfa(userId, secret);
            List<String> codes = mfaService.generateBackupCodes(userId);
            return ResponseEntity.ok().body(codes);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Failed to enable MFA");
        }
    }

    @PostMapping("/disable")
    public ResponseEntity<?> disableMfa(@RequestParam Long userId) {
        try {
            mfaService.disableMfa(userId);
            return ResponseEntity.ok().body("MFA disabled successfully");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Failed to disable MFA");
        }
    }

    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticateWithBackupCode(@RequestParam String code) {
        try {
            boolean valid = mfaService.validateBackupCode(code);
            if (valid) {
                return ResponseEntity.ok().body("Authentication successful");
            } else {
                return ResponseEntity.status(401).body("Invalid or expired backup code");
            }
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Authentication failed");
        }
    }
}